    41→  const badges: BadgeMap = {};
    42→  if (handoffs > 0) badges["/app/chat"] = { count: handoffs, variant: "orange" };
    43→  if (botWarning > 0) badges["/app/agent"] = { count: 1, variant: "yellow" };
    44→  badges["/app/support"]      = { count: 1, variant: "red" };
    45→  badges["/app/orders"]       = { count: 3, variant: "orange" };
    46→  badges["/app/appointments"] = { count: 4, variant: "blue" };
    47→  return badges;
