    18→function useCountUp(end: number, duration: number = 2000) {
    19→  const [count, setCount] = useState(0);
    20→  const [hasAnimated, setHasAnimated] = useState(false);
    21→  const ref = useRef<HTMLSpanElement>(null);
    22→
    23→  useEffect(() => {
    24→    const observer = new IntersectionObserver((entries) => {
    25→      if (entries[0].isIntersecting && !hasAnimated) {
    26→        setHasAnimated(true);
    27→        let startTimestamp: number | null = null;
    28→        const step = (timestamp: number) => {
    29→          if (!startTimestamp) startTimestamp = timestamp;
    30→          const progress = Math.min((timestamp - startTimestamp) / duration, 1);
    31→          setCount(Math.floor(progress * end));
    32→          if (progress < 1) {
    33→            window.requestAnimationFrame(step);
    34→          }
    35→        };
    36→        window.requestAnimationFrame(step);
    37→      }
    38→    }, { threshold: 0.1 });
    39→
    40→    if (ref.current) observer.observe(ref.current);
    41→    return () => observer.disconnect();
    42→  }, [end, duration, hasAnimated]);
    43→
    44→  return { count, ref };
    45→}
