   119→      className={`rounded-3xl border overflow-hidden flex flex-col group cursor-pointer transition-shadow hover:shadow-2xl ${
   120→        darkMode ? "bg-slate-900 border-slate-700 text-white" : "bg-white border-slate-100 text-slate-900"
   121→      }`}
   122→      onClick={() => onQuickView(p)}
   123→    >
   124→      <div className={`aspect-square relative overflow-hidden flex items-center justify-center ${darkMode ? "bg-slate-800" : "bg-slate-50"}`}>
   125→        <span className={`absolute top-3 left-3 text-[9px] font-mono px-2 py-0.5 rounded z-10 ${darkMode ? "bg-slate-700 text-slate-400" : "bg-slate-100 text-slate-400"}`}>
   126→          #{p.id}
   127→        </span>
   128→        {p.destacado && <span className="absolute top-9 left-3 bg-amber-400 text-amber-900 px-3 py-0.5 rounded-full text-[9px] font-black uppercase z-10">⭐ Destacado</span>}
   129→        {isOffer && <Badge color="#ef4444">¡Oferta!</Badge>}
   130→        {isNew && !isOffer && <Badge color="#0ea5e9">Nuevo</Badge>}
   131→        {(p.stock === "0" || p.stock === "false" || p.stock === "FALSE" || p.stock === "sin stock" || p.stock === "Sin stock") && (
   132→          <span className="absolute bottom-3 left-3 bg-slate-800/80 text-white px-3 py-0.5 rounded-full text-[9px] font-black uppercase z-10">Sin stock</span>
   133→        )}
   134→
   135→        {p.imagen ? (
   136→          <img
   137→            src={p.imagen}
   138→            alt={p.nombre}
   139→            className="w-full h-full object-contain group-hover:scale-110 transition-transform duration-500"
   140→            referrerPolicy="no-referrer"
   141→            loading="lazy"
   142→          />
   143→        ) : (
   144→          <div className="w-20 h-20 rounded-2xl flex items-center justify-center" style={{ background: `${primary}20` }}>
   145→            <ShoppingCart className="w-8 h-8 opacity-40" style={{ color: primary }} />
   146→          </div>
   147→        )}
   148→
   149→        <div className="absolute inset-0 bg-slate-900/50 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2 z-20">
   150→          <button
   151→            onClick={(e) => { e.stopPropagation(); onQuickView(p); }}
   152→            className="bg-white text-slate-900 px-3 py-2 rounded-full font-bold text-xs shadow-md transform translate-y-4 group-hover:translate-y-0 transition-all duration-300 flex items-center gap-1.5 hover:bg-slate-100"
   153→          >
   154→            <Eye size={13} /> Vista rápida
   155→          </button>
   156→        </div>
   157→      </div>
   158→
   159→      <div className="p-5 flex flex-col flex-grow">
   160→        <div className="flex items-center justify-between mb-2">
   161→          <span className="text-[9px] font-black uppercase" style={{ color: primary }}>{p.categoria}</span>
   162→          <label
   163→            className="flex items-center gap-1 cursor-pointer select-none"
   164→            onClick={(e) => e.stopPropagation()}

